static FAIL_ON_ALLOCATION: AtomicUsize = AtomicUsize::new(usize::MAX);

#[cfg(unix)]
#[global_allocator]
static GLOBAL_ALLOCATOR: FailingAlloc = FailingAlloc;

#[cfg(unix)]
unsafe impl GlobalAlloc for FailingAlloc {
