#[cfg(all(test, unix))]
#[derive(Debug)]
struct ProbeReport {
    target: usize,
    arg_panic_caught: bool,
    baseline_args: Vec<String>,
    args_visible_after_catch: Vec<String>,
    spawn_succeeded: bool,
    raw_os_error: Option<i32>,
