#[cfg(all(test, unix))]
fn probe(target: usize) -> ProbeReport {
    let current_exe = std::env::current_exe().expect("current test executable path");
    let mut cmd = Command::new(current_exe);
    cmd.env(CHILD_ENV, "1");
    cmd.stdout(Stdio::piped());
    cmd.stderr(Stdio::inherit());
