#[cfg(all(test, unix))]
impl PanicHookGuard {
    fn install() -> Self {
        let previous_hook = std::panic::take_hook();
        std::panic::set_hook(Box::new(|_| {}));
        Self(Some(previous_hook))
    }
}

#[cfg(all(test, unix))]
impl Drop for PanicHookGuard {
    fn drop(&mut self) {
        if let Some(previous_hook) = self.0.take() {
            std::panic::set_hook(previous_hook);
        }
    }
}

