struct AllocErrorHookGuard(fn(Layout));

#[cfg(all(test, unix))]
impl AllocErrorHookGuard {
    fn install() -> Self {
        let previous_hook = take_alloc_error_hook();
        set_alloc_error_hook(|_| panic!("reproducer alloc error"));
